import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Empty / processing fee
  it.todo("empty item list yields premium of 5 G (processing fee only)");

  // Base premiums for main items
  it.todo("quote a plain amulet for a fresh customer (60 base + 10 first + 5 fee = 75 G)");
  it.todo("quote a plain sword for a fresh customer (100 base + 10 first + 5 fee = 115 G)");
  it.todo("quote a plain staff for a fresh customer (80 base + 10 first + 5 fee = 95 G)");
  it.todo("quote a plain potion for a fresh customer (40 base + 10 first + 5 fee = 55 G)");

  // Components
  it.todo("quote 2 runes (no block): 50 base + 10 first + 5 fee = 65 G");
  it.todo("quote 3 runes (block applies): 60 base + 10 first + 5 fee = 75 G");
  it.todo("quote 4 runes (no block — block requires exactly 3): 100 base + 10 first + 5 fee = 115 G");
  it.todo("quote 7 runes: 175 base + 10 first + 5 fee = 195 G");
  it.todo("quote 2 runes + 1 moonstone (no block, different types): 75 base + 10 first + 5 fee = 95 G");
  it.todo("quote 3 runes + 3 moonstones (two separate blocks): 120 base + 10 first + 5 fee = 140 G");

  // Item-specific modifiers
  it.todo("cursed sword (fresh customer): 100 base + 50 curse + 10 first + 5 fee = 165 G");
  it.todo("highly enchanted sword at exactly 5 (fresh customer): 100 base + 30 high-ench + 10 first + 5 fee = 145 G");
  it.todo("sword with enchantment 4 (fresh): no high-ench surcharge → 115 G");
  it.todo("cursed sword with enchantment 5 (fresh): both surcharges apply → 100 + 50 + 30 + 10 + 5 = 195 G");

  // Multi-item policies — modifier scope
  it.todo("policy with cursed sword + plain amulet (fresh): 160 base + 50 curse + 16 first + 5 fee = 231 G");

  // Policy-wide modifiers
  it.todo("loyalty: 2 years with MHPCO, plain sword: 100 base + 10 first - 20 loyalty + 5 fee = 95 G");
  it.todo("follow-up contract: second quote in scenario for 3-year customer with cursed sword, ench 7 → 160 G");

  // Rounding
  it.todo("premium with fractional intermediate values rounds up to whole G in MHPCO favor");

  // Unknown item type
  it.todo("quote with unknown item type causes runScenario to throw");

  // Claim — base reimbursement
  it.todo("claim: regular sword, damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("claim: rune damaged 200 → payout 100 (no special clause; deductible applies)");

  // Claim — special clauses
  it.todo("claim: high-enchantment sword (ench 8), damage 1000 → 500 then -100 deductible = 400");
  it.todo("claim: dragon-material sword, damage 1000 → 1000 - 100 = 900");
  it.todo("claim: dragon-material sword ench 9, damage 1000 → 50% wins, then deductible = 400");
  it.todo("claim: dragon-material sword ench 5, damage 800 → only dragon clause: 800 - 100 = 700");

  // Claim — multi-item & deductible per damage event
  it.todo("claim: dragon-cause damages a sword (500) and an amulet (300) → 400 + 200 = 600");
  it.todo("claim: two swords insured, two sword damages each 500 → each treated separately");

  // Cap exhaustion
  it.todo("claim: sword (cap 2000), two claims 1500 G each → first 1400/600 remaining, second 600/0");
  it.todo("claim: cursed sword cap is based on unmodified insurance value (cap 2000)");

  // Claim errors
  it.todo("claim: damages contains more entries of a type than insured → throws");
  it.todo("claim: damage entry refers to item not in policy → throws");
  it.todo("claim: damage entry with negative amount → throws");

  // Claim payout rounding
  it.todo("claim payout with fractional value rounds DOWN to whole G in MHPCO favor");
});

