export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause?: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioOutput {
  results: StepResult[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const itemBasePremium = (item: Item): number => {
  if (isComponent(item)) return 25;
  return BASE_PREMIUMS[item.type] ?? 0;
};

export const runScenario = (scenario: Scenario): ScenarioOutput => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const policyBase = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
      const firstInsurance = policyBase * 0.1;
      const total = policyBase + firstInsurance + 5;
      return { premium: Math.ceil(total) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

