export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause?: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioOutput {
  results: StepResult[];
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const itemBasePremium = (item: Item): number => {
  if (isComponent(item)) return 25;
  return BASE_PREMIUMS[item.type] ?? 0;
};

const policyBasePremium = (items: Item[]): number => {
  // Components: group by type; each group of exactly 3 alike → 60 G block, otherwise 25 G each
  const componentCounts: Record<string, number> = {};
  let nonComponentTotal = 0;
  for (const item of items) {
    if (isComponent(item)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      nonComponentTotal += itemBasePremium(item);
    }
  }
  let componentTotal = 0;
  for (const count of Object.values(componentCounts)) {
    componentTotal += count === 3 ? 60 : count * 25;
  }
  return nonComponentTotal + componentTotal;
};

const itemModifiers = (item: Item): number => {
  let mod = 0;
  const base = itemBasePremium(item);
  if (item.cursed) mod += base * 0.5;
  if ((item.enchantment ?? 0) >= 5) mod += base * 0.3;
  return mod;
};

export const runScenario = (scenario: Scenario): ScenarioOutput => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const policyBase = policyBasePremium(step.items);
      const itemSurcharges = step.items.reduce((sum, item) => sum + itemModifiers(item), 0);
      const firstInsurance = policyBase * 0.1;
      const total = policyBase + itemSurcharges + firstInsurance + 5;
      return { premium: Math.ceil(total) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

